"""Report generation: markdown and JSON output."""

from __future__ import annotations

from datetime import datetime, timezone
from pathlib import Path

from govai.models import (
    ConfidenceSource,
    InventoryReport,
    RiskTier,
)

# Order for risk tiers in the report
_TIER_ORDER = [
    RiskTier.UNACCEPTABLE,
    RiskTier.HIGH,
    RiskTier.LIMITED,
    RiskTier.MINIMAL,
    RiskTier.UNCLEAR,
]

_DISCLAIMER = (
    "This report is generated by govai and is a starting point for EU "
    "AI Act compliance review. It is not a legal opinion. Classifications "
    "marked 'inferred' should be verified. govai is open source: "
    "github.com/kevin-chacon/govai-eu"
)

